242	    private CriticalActionRequestEntity requireRequest(Long requestId, UserEntity actor, Permission permission) {
243	        CriticalActionRequestEntity request = requestRepository.findById(requestId)
244	            .orElseThrow(() -> new ApiException(404, "Critical action request not found", List.of("requestId=" + requestId)));
245	        boolean allowed = permissionAuthorizationService.canAccessResource(
246	            actor,
247	            permission,
248	            request.getRequestedBy().getId(),
249	            request.getRequestedBy().getRole().getName(),
250	            request.getRequestedBy().getOrganizationCode()
251	        );
252	        if (!allowed) {
253	            throw new ApiException(403, "Access denied", List.of("CRITICAL_ACTION_SCOPE_RESTRICTION", "requestId=" + requestId));
254	        }
255	        return request;
256	    }
