282	            approvals.stream().map(item -> new CriticalActionApprovalResponse(item.getId(), item.getApproverUser().getDisplayName(), item.getDecision().name(), item.getComments(), item.getCreatedAt())).toList(),
283	            auditRepository.findByRequestIdOrderByCreatedAtAsc(request.getId()).stream().map(item -> new CriticalActionAuditResponse(item.getAction().name(), item.getActorUser().getDisplayName(), item.getDetail(), item.getCreatedAt())).toList()
284	        );
