import java.io.IOException;
import java.time.Clock;
import java.time.Instant;
import java.util.ArrayDeque;
import java.util.Deque;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import org.springframework.http.MediaType;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.AnonymousAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

@Component
public class RateLimitFilter extends OncePerRequestFilter {

    private static final int MAX_REQUESTS_PER_MINUTE = 60;
    private static final int MAX_LOGIN_REQUESTS_PER_MINUTE = 20;
    private final Map<String, Deque<Instant>> requestWindows = new ConcurrentHashMap<>();
    private final Map<String, Deque<Instant>> ipRequestWindows = new ConcurrentHashMap<>();
    private final Clock clock;
    private final ObjectMapper objectMapper;

    @Autowired
    public RateLimitFilter(ObjectMapper objectMapper) {
        this(objectMapper, Clock.systemUTC());
    }

    RateLimitFilter(ObjectMapper objectMapper, Clock clock) {
        this.objectMapper = objectMapper;
        this.clock = clock;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        return path.startsWith("/api/health") || path.startsWith("/api/meta") || path.startsWith("/actuator");
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        String path = request.getRequestURI();

        if (path.startsWith("/api/auth/")) {
            String clientIp = resolveClientIp(request);
            int limit = path.startsWith("/api/auth/login") ? MAX_LOGIN_REQUESTS_PER_MINUTE : MAX_REQUESTS_PER_MINUTE;
            String detail = limit == MAX_LOGIN_REQUESTS_PER_MINUTE ? "MAX_20_LOGIN_REQUESTS_PER_MINUTE" : "MAX_60_REQUESTS_PER_MINUTE";
            if (isRateLimited(ipRequestWindows, clientIp, limit)) {
                writeRateLimitResponse(response, detail);
                return;
            }
            filterChain.doFilter(request, response);
            return;
        }

        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated() || authentication instanceof AnonymousAuthenticationToken) {
            filterChain.doFilter(request, response);
            return;
        }

        String key = authentication.getName();
        if (isRateLimited(requestWindows, key, MAX_REQUESTS_PER_MINUTE)) {
            writeRateLimitResponse(response, "MAX_60_REQUESTS_PER_MINUTE");
            return;
        }

        filterChain.doFilter(request, response);
    }

    private boolean isRateLimited(Map<String, Deque<Instant>> windows, String key, int maxRequests) {
        Deque<Instant> window = windows.computeIfAbsent(key, ignored -> new ArrayDeque<>());
        Instant now = clock.instant();
        synchronized (window) {
            while (!window.isEmpty() && window.peekFirst().isBefore(now.minusSeconds(60))) {
                window.pollFirst();
            }
            if (window.size() >= maxRequests) {
                return true;
            }
            window.addLast(now);
        }
        return false;
    }

    private void writeRateLimitResponse(HttpServletResponse response, String detail) throws IOException {
        response.setStatus(429);
        response.setContentType(MediaType.APPLICATION_JSON_VALUE);
        objectMapper.writeValue(response.getOutputStream(), new ApiErrorResponse(429, "Rate limit exceeded", List.of(detail)));
    }

    private String resolveClientIp(HttpServletRequest request) {
        String forwarded = request.getHeader("X-Forwarded-For");
        if (forwarded != null && !forwarded.isBlank()) {
            return forwarded.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    void clearWindows() {
        requestWindows.clear();
        ipRequestWindows.clear();
    }
}
