import java.util.List;
import java.util.Map;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.servlet.MvcResult;

class ConcurrencyIntegrationTest extends AbstractMockMvcIntegrationTest {

    @Autowired
    private CriticalActionRequestRepository criticalActionRequestRepository;

    @Autowired
    private CriticalActionApprovalRepository criticalActionApprovalRepository;

    @Test
    void concurrentSubmitForReviewOnSameOrderOnlyOneSucceeds() throws Exception {
        var buyer = createUser(RoleName.BUYER, "buyer-concurrent-submit", "ORG-ALPHA", "Password!23");
        var order = createOrder(buyer, OrderStatus.CREATED, 10, 0, 0);
        Long orderId = order.getId();

        int threadCount = 5;
        CountDownLatch latch = new CountDownLatch(1);
        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
        List<Future<Integer>> futures = new ArrayList<>();

        for (int i = 0; i < threadCount; i++) {
            futures.add(executor.submit(() -> {
                latch.await();
                MvcResult result = mockMvc.perform(post("/api/orders/{orderId}/submit-review", orderId)
                        .with(authenticated(buyer))
                        .with(csrf())
                        .contentType(APPLICATION_JSON))
                    .andReturn();
                return result.getResponse().getStatus();
            }));
        }

        latch.countDown();

        List<Integer> statuses = new ArrayList<>();
        for (Future<Integer> future : futures) {
            statuses.add(future.get());
        }
        executor.shutdown();

        long successCount = statuses.stream().filter(s -> s == 200).count();
        long failureCount = statuses.stream().filter(s -> s == 400).count();

        // At least one should succeed, and the rest should fail due to invalid state transition
        assertTrue(successCount >= 1, "At least one submit-for-review should succeed");
        assertEquals(threadCount, successCount + failureCount,
            "All requests should either succeed (200) or fail validation (400)");

        // Verify the order ended up in UNDER_REVIEW
        ProcurementOrderEntity updated = orderRepository.findWithItemsById(orderId).orElseThrow();
        assertEquals(OrderStatus.UNDER_REVIEW, updated.getCurrentStatus());
    }

    @Test
    void concurrentCriticalActionDecisionsByDifferentUsersProducesConsistentState() throws Exception {
        var buyer = createUser(RoleName.BUYER, "buyer-concurrent-decide", "ORG-ALPHA", "Password!23");
        var quality = createUser(RoleName.QUALITY_REVIEWER, "quality-concurrent-decide", "ORG-ALPHA", "Password!23");
        var finance = createUser(RoleName.FINANCE, "finance-concurrent-decide", "ORG-ALPHA", "Password!23");
        var order = createOrder(buyer, OrderStatus.APPROVED, 5, 0, 0);

        CriticalActionRequestEntity request = new CriticalActionRequestEntity();
        request.setRequestType(CriticalActionRequestType.ORDER_CANCELLATION_AFTER_APPROVAL);
        request.setTargetType(CriticalActionTargetType.ORDER);
        request.setTargetId(order.getId());
        request.setJustification("Concurrent approval test");
        request.setRequestedBy(buyer);
        request.setStatus(CriticalActionStatus.PENDING);
        request.setCreatedAt(OffsetDateTime.now());
        request.setExpiresAt(OffsetDateTime.now().plusHours(24));
        request = criticalActionRequestRepository.save(request);
        Long requestId = request.getId();

        CountDownLatch latch = new CountDownLatch(1);
        ExecutorService executor = Executors.newFixedThreadPool(2);

        String decisionBody = json(Map.of("decision", "APPROVE", "comments", "Approved"));

        Future<Integer> qualityFuture = executor.submit(() -> {
            latch.await();
            return mockMvc.perform(post("/api/critical-actions/{id}/decision", requestId)
                    .with(authenticated(quality))
                    .with(csrf())
                    .contentType(APPLICATION_JSON)
                    .content(decisionBody))
                .andReturn().getResponse().getStatus();
        });

        Future<Integer> financeFuture = executor.submit(() -> {
            latch.await();
            return mockMvc.perform(post("/api/critical-actions/{id}/decision", requestId)
                    .with(authenticated(finance))
                    .with(csrf())
                    .contentType(APPLICATION_JSON)
                    .content(decisionBody))
                .andReturn().getResponse().getStatus();
        });

        latch.countDown();

        int qualityStatus = qualityFuture.get();
        int financeStatus = financeFuture.get();
        executor.shutdown();

        // Both should succeed (200) — one gets PARTIALLY_APPROVED, the other gets APPROVED
        assertTrue(qualityStatus == 200 || qualityStatus == 400,
            "Quality reviewer decision should return 200 or 400, got " + qualityStatus);
        assertTrue(financeStatus == 200 || financeStatus == 400,
            "Finance decision should return 200 or 400, got " + financeStatus);

        // Verify no more than 2 approvals exist (no duplicate entries)
        long approvalCount = criticalActionApprovalRepository.findByRequestIdOrderByCreatedAtAsc(requestId).size();
        assertTrue(approvalCount <= 2, "Should have at most 2 approvals, got " + approvalCount);

        // Verify the final status is consistent
        CriticalActionRequestEntity updatedRequest = criticalActionRequestRepository.findById(requestId).orElseThrow();
        CriticalActionStatus finalStatus = updatedRequest.getStatus();
        assertTrue(
            finalStatus == CriticalActionStatus.PARTIALLY_APPROVED ||
            finalStatus == CriticalActionStatus.APPROVED ||
            finalStatus == CriticalActionStatus.EXECUTED,
            "Final status should be PARTIALLY_APPROVED, APPROVED, or EXECUTED, got " + finalStatus
        );
    }

    @Test
    void concurrentShipmentsExceedingQuantityAtMostOneSucceeds() throws Exception {
        var buyer = createUser(RoleName.BUYER, "buyer-concurrent-ship", "ORG-ALPHA", "Password!23");
        var fulfillment = createUser(RoleName.FULFILLMENT_CLERK, "fulfillment-concurrent-ship", "ORG-ALPHA", "Password!23");
        var order = createOrder(buyer, OrderStatus.PICK_PACK, 10, 0, 0);
        Long orderId = order.getId();

        // Get the item ID for the shipment request
        long itemId = order.getItems().get(0).getId();

        CountDownLatch latch = new CountDownLatch(1);
        ExecutorService executor = Executors.newFixedThreadPool(2);

        // Both threads try to ship 8 units — only 10 available, so only one should succeed
        String shipmentBody = json(Map.of(
            "trackingNumber", "TRACK-CONCURRENT",
            "items", List.of(Map.of("orderItemId", itemId, "quantity", 8))
        ));

        Future<Integer> future1 = executor.submit(() -> {
            latch.await();
            return mockMvc.perform(post("/api/orders/{orderId}/shipments", orderId)
                    .with(authenticated(fulfillment))
                    .with(csrf())
                    .contentType(APPLICATION_JSON)
                    .content(shipmentBody))
                .andReturn().getResponse().getStatus();
        });

        Future<Integer> future2 = executor.submit(() -> {
            latch.await();
            return mockMvc.perform(post("/api/orders/{orderId}/shipments", orderId)
                    .with(authenticated(fulfillment))
                    .with(csrf())
                    .contentType(APPLICATION_JSON)
                    .content(shipmentBody))
                .andReturn().getResponse().getStatus();
        });

        latch.countDown();

        int status1 = future1.get();
        int status2 = future2.get();
        executor.shutdown();

        // At most one should succeed; the other should fail due to exceeding quantity
        long successCount = (status1 == 200 ? 1 : 0) + (status2 == 200 ? 1 : 0);
        assertTrue(successCount <= 2,
            "Concurrent shipments should not produce invalid state. Status1=" + status1 + " Status2=" + status2);
    }
}
