1	import { Component, OnInit } from '@angular/core';
2	import { CommonModule } from '@angular/common';
3	import { FormArray, FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
4	import { Router } from '@angular/router';
5	import { catchError, finalize, forkJoin, of } from 'rxjs';
6	import { MatCardModule } from '@angular/material/card';
7	import { MatButtonModule } from '@angular/material/button';
8	import { MatFormFieldModule } from '@angular/material/form-field';
9	import { MatInputModule } from '@angular/material/input';
10	import { MatSelectModule } from '@angular/material/select';
11	import { MatTableModule } from '@angular/material/table';
12	import { MatSnackBar } from '@angular/material/snack-bar';
13	import { OrderService } from '../../../core/services/order.service';
14	import { OrderSummaryModel, ProductCatalogModel } from '../../../core/models/order.models';
15	import { OrderStatusBadgeComponent } from '../shared/order-status-badge.component';
16	
17	@Component({
18	  selector: 'app-order-workspace',
19	  standalone: true,
20	  imports: [CommonModule, ReactiveFormsModule, MatCardModule, MatButtonModule, MatFormFieldModule, MatInputModule, MatSelectModule, MatTableModule, OrderStatusBadgeComponent],
21	  templateUrl: './order-workspace.component.html',
22	  styleUrl: './order-workspace.component.scss'
23	})
24	export class OrderWorkspaceComponent implements OnInit {
25	  catalog: ProductCatalogModel[] = [];
26	  orders: OrderSummaryModel[] = [];
27	  isLoading = true;
28	  loadError = '';
29	  isCreatingDraft = false;
30	  readonly reviewSubmittingIds = new Set<number>();
31	  readonly cancelSubmittingIds = new Set<number>();
32	  readonly columns = ['orderNumber', 'status', 'ordered', 'shipped', 'received'];
33	
34	  readonly form = this.fb.group({
35	    notes: [''],
36	    items: this.fb.array([this.createItemRow()])
37	  });
38	
39	  constructor(
40	    private readonly fb: FormBuilder,
41	    private readonly orderService: OrderService,
42	    private readonly snackBar: MatSnackBar,
43	    private readonly router: Router
44	  ) {}
45	
46	  ngOnInit(): void {
47	    this.reload();
48	  }
49	
50	  get items(): FormArray {
51	    return this.form.get('items') as FormArray;
52	  }
53	
54	  addRow(): void {
55	    this.items.push(this.createItemRow());
56	  }
57	
58	  submit(): void {
59	    if (this.isCreatingDraft) {
60	      return;
61	    }
62	    if (this.form.invalid) {
63	      this.form.markAllAsTouched();
64	      return;
65	    }
66	    const payload = {
67	      notes: this.form.value.notes,
68	      items: this.items.getRawValue().filter((item) => item.productId).map((item) => ({ productId: item.productId, quantity: Number(item.quantity) }))
69	    };
70	    this.isCreatingDraft = true;
71	    this.orderService.createOrder(payload).pipe(
72	      finalize(() => (this.isCreatingDraft = false))
73	    ).subscribe({
74	      next: (order) => {
75	        this.snackBar.open('Order created', 'Dismiss', { duration: 2500 });
76	        this.router.navigate(['/orders', order.id]);
77	      }
78	    });
79	  }
80	
81	  submitForReview(orderId: number): void {
82	    if (this.reviewSubmittingIds.has(orderId)) {
83	      return;
84	    }
85	    this.reviewSubmittingIds.add(orderId);
86	    this.orderService.submitForReview(orderId).pipe(
87	      finalize(() => this.reviewSubmittingIds.delete(orderId))
88	    ).subscribe({
89	      next: () => {
90	        this.snackBar.open('Order submitted for review', 'Dismiss', { duration: 2500 });
91	        this.reload();
92	      }
93	    });
94	  }
95	
96	  cancel(orderId: number): void {
97	    if (this.cancelSubmittingIds.has(orderId)) {
98	      return;
99	    }
100	    this.cancelSubmittingIds.add(orderId);
101	    this.orderService.cancelOrder(orderId).pipe(
102	      finalize(() => this.cancelSubmittingIds.delete(orderId))
103	    ).subscribe({
104	      next: () => {
105	        this.snackBar.open('Order canceled', 'Dismiss', { duration: 2500 });
106	        this.reload();
107	      }
108	    });
109	  }
110	
111	  openOrder(orderId: number): void {
112	    this.router.navigate(['/orders', orderId]);
113	  }
114	
115	  isSubmitForReviewPending(orderId: number): boolean {
116	    return this.reviewSubmittingIds.has(orderId);
117	  }
118	
119	  isCancelPending(orderId: number): boolean {
120	    return this.cancelSubmittingIds.has(orderId);
121	  }
122	
123	  private reload(): void {
124	    this.isLoading = true;
125	    this.loadError = '';
126	    forkJoin({
127	      catalog: this.orderService.listCatalog(),
128	      orders: this.orderService.listOrders()
129	    }).pipe(
130	      catchError(() => {
131	        this.loadError = 'Order workspace data could not be loaded right now.';
132	        this.isLoading = false;
133	        return of({ catalog: [], orders: [] });
134	      })
135	    ).subscribe({
136	      next: ({ catalog, orders }) => {
137	        this.catalog = catalog;
138	        this.orders = orders;
139	        this.isLoading = false;
140	      }
141	    });
142	  }
143	
144	  private createItemRow() {
145	    return this.fb.group({
146	      productId: [null, Validators.required],
147	      quantity: [1, [Validators.required, Validators.min(1)]]
148	    });
149	  }
150	}
