12	import { DocumentCenterService } from '../../../core/services/document-center.service';
13	import {
14	  DocumentArchiveModel,
15	  DocumentDetailModel,
16	  DocumentPreviewModel,
17	  DocumentSummaryModel,
18	  DocumentTemplateModel,
19	  DocumentTypeModel
20	} from '../../../core/models/document.models';
