31	export class DocumentCenterComponent implements OnInit {
32	  private readonly dialog = inject(MatDialog);
33	
34	  readonly authUser = this.authService.userSnapshot();
35	  readonly canManageTemplates = this.authUser?.role === 'SYSTEM_ADMINISTRATOR';
36	  readonly canApprove = this.authUser?.role === 'QUALITY_REVIEWER' || this.authUser?.role === 'SYSTEM_ADMINISTRATOR';
37	  readonly canArchive = this.authUser?.role === 'SYSTEM_ADMINISTRATOR';
38	  readonly canRequestCriticalAction = this.authUser?.role === 'BUYER' || this.authUser?.role === 'SYSTEM_ADMINISTRATOR';
39	
40	  documentTypes: DocumentTypeModel[] = [];
41	  templates: DocumentTemplateModel[] = [];
42	  documents: DocumentSummaryModel[] = [];
43	  approvalQueue: DocumentSummaryModel[] = [];
44	  archives: DocumentArchiveModel[] = [];
45	  selectedDocument: DocumentDetailModel | null = null;
46	  selectedFile: File | null = null;
47	  isLoading = true;
48	  loadError = '';
49	  private readonly pendingActions = new Set<string>();
50	
