123	  openDocument(id: number): void {
124	    this.documentCenterService.getDocument(id).subscribe({ next: (document) => (this.selectedDocument = document) });
125	  }
126	
127	  submitForApproval(id: number): void {
128	    const actionKey = this.documentActionKey('submit', id);
129	    if (!this.startAction(actionKey)) {
130	      return;
131	    }
132	    this.documentCenterService.submitForApproval(id).pipe(
133	      finalize(() => this.finishAction(actionKey))
134	    ).subscribe({
135	      next: (document) => {
136	        this.selectedDocument = document;
137	        this.snackBar.open('Document submitted for approval', 'Dismiss', { duration: 2200 });
138	        this.reload();
139	      }
140	    });
141	  }
142	
143	  approve(id: number): void {
144	    const actionKey = this.documentActionKey('approve', id);
145	    if (!this.startAction(actionKey)) {
146	      return;
147	    }
148	    this.documentCenterService.approve(id, 'Approved from Quality Reviewer queue.').pipe(
149	      finalize(() => this.finishAction(actionKey))
150	    ).subscribe({
151	      next: (document) => {
152	        this.selectedDocument = document;
153	        this.snackBar.open('Document approved', 'Dismiss', { duration: 2200 });
154	        this.reload();
155	      }
156	    });
157	  }
158	
159	  archive(id: number): void {
160	    const actionKey = this.documentActionKey('archive', id);
161	    if (!this.startAction(actionKey)) {
162	      return;
163	    }
164	    this.documentCenterService.archive(id).pipe(
165	      finalize(() => this.finishAction(actionKey))
166	    ).subscribe({
167	      next: (document) => {
168	        this.selectedDocument = document;
169	        this.snackBar.open('Document archived', 'Dismiss', { duration: 2200 });
170	        this.reload();
171	      }
172	    });
173	  }
174	
175	  preview(id: number): void {
176	    const actionKey = this.documentActionKey('preview', id);
177	    if (!this.startAction(actionKey)) {
178	      return;
179	    }
180	    forkJoin({ preview: this.documentCenterService.preview(id), blob: this.documentCenterService.fetchContentBlob(id) }).pipe(
181	      finalize(() => this.finishAction(actionKey))
182	    ).subscribe({
183	      next: ({ preview, blob }) => {
184	        const objectUrl = URL.createObjectURL(blob);
185	        const dialogRef = this.dialog.open(DocumentPreviewDialogComponent, {
186	          width: '960px',
187	          data: { preview, previewObjectUrl: objectUrl }
188	        });
189	        dialogRef.afterClosed().subscribe(() => URL.revokeObjectURL(objectUrl));
190	      },
191	      error: () => this.snackBar.open('Preview is unavailable for this document.', 'Dismiss', { duration: 2600 })
192	    });
193	  }
194	
195	  requestDestruction(id: number): void {
196	    const actionKey = this.documentActionKey('request-destruction', id);
197	    if (!this.startAction(actionKey)) {
198	      return;
199	    }
200	    this.criticalActionService.create({ requestType: 'DOCUMENT_DESTRUCTION', targetType: 'DOCUMENT', targetId: id, justification: 'Document destruction requires dual approval.' })
201	      .pipe(finalize(() => this.finishAction(actionKey)))
202	      .subscribe({ next: () => this.snackBar.open('Document destruction request created', 'Dismiss', { duration: 2200 }) });
203	  }
204	
205	  requestRetentionOverride(id: number): void {
206	    const actionKey = this.documentActionKey('request-retention', id);
207	    if (!this.startAction(actionKey)) {
208	      return;
209	    }
210	    this.criticalActionService.create({ requestType: 'RETENTION_OVERRIDE', targetType: 'DOCUMENT', targetId: id, justification: 'Retention override requested for controlled record.' })
211	      .pipe(finalize(() => this.finishAction(actionKey)))
212	      .subscribe({ next: () => this.snackBar.open('Retention override request created', 'Dismiss', { duration: 2200 }) });
213	  }
214	
215	  isActionPending(actionKey: string): boolean {
216	    return this.pendingActions.has(actionKey);
217	  }
218	
219	  draftActionKey(): string {
220	    return 'draft:create';
221	  }
222	
223	  templateActionKey(): string {
224	    return 'template:create';
225	  }
226	
227	  documentActionKey(action: string, id: number): string {
228	    return `${action}:${id}`;
229	  }
230	
231	  private reload(): void {
232	    this.isLoading = true;
233	    this.loadError = '';
234	    forkJoin({
235	      types: this.documentCenterService.listTypes().pipe(catchError(() => of([]))),
236	      templates: this.documentCenterService.listTemplates().pipe(catchError(() => of([]))),
237	      documents: this.documentCenterService.listDocuments().pipe(catchError(() => of([]))),
238	      queue: (this.canApprove ? this.documentCenterService.approvalQueue() : of([])).pipe(catchError(() => of([]))),
239	      archives: this.documentCenterService.archiveList().pipe(catchError(() => of([])))
240	    }).subscribe({
241	      next: ({ types, templates, documents, queue, archives }) => {
242	        this.documentTypes = types;
243	        this.templates = templates;
244	        this.documents = documents;
245	        this.approvalQueue = queue;
246	        this.archives = archives;
247	        this.isLoading = false;
248	      }
249	    });
250	  }
251	
252	  private startAction(actionKey: string): boolean {
253	    if (this.pendingActions.has(actionKey)) {
254	      return false;
255	    }
256	    this.pendingActions.add(actionKey);
257	    return true;
258	  }
259	
260	  private finishAction(actionKey: string): void {
261	    this.pendingActions.delete(actionKey);
262	  }
263	
264	}
