import java.lang.reflect.Constructor;
import java.lang.reflect.RecordComponent;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

/**
 * Strips HTML tags from user-supplied text as defense-in-depth against stored XSS.
 * Tag stripping (not HTML-escaping) is used to avoid double-encoding with Angular's
 * automatic output escaping in {{ }} interpolation bindings.
 */
public final class TextSanitizer {

    private static final Pattern HTML_TAG_PATTERN = Pattern.compile("<[^>]*>");

    private TextSanitizer() {
    }

    public static String stripHtmlTags(String input) {
        if (input == null) {
            return null;
        }
        return HTML_TAG_PATTERN.matcher(input).replaceAll("");
    }

    @SuppressWarnings("unchecked")
    public static Object sanitizeObject(Object obj) {
        if (obj == null) {
            return null;
        }
        if (obj instanceof String s) {
            return stripHtmlTags(s);
        }
        if (obj instanceof List<?> list) {
            return list.stream().map(TextSanitizer::sanitizeObject).toList();
        }
        Class<?> clazz = obj.getClass();
        if (!clazz.isRecord()) {
            return obj;
        }
        try {
            RecordComponent[] components = clazz.getRecordComponents();
            Class<?>[] componentTypes = Arrays.stream(components)
                    .map(RecordComponent::getType)
                    .toArray(Class[]::new);
            Object[] values = new Object[components.length];
            for (int i = 0; i < components.length; i++) {
                Object value = components[i].getAccessor().invoke(obj);
                if (value instanceof String s) {
                    values[i] = stripHtmlTags(s);
                } else if (value instanceof List<?> || (value != null && value.getClass().isRecord())) {
                    values[i] = sanitizeObject(value);
                } else {
                    values[i] = value;
                }
            }
            Constructor<?> canonical = clazz.getDeclaredConstructor(componentTypes);
            canonical.setAccessible(true);
            return canonical.newInstance(values);
        } catch (ReflectiveOperationException e) {
            return obj;
        }
    }
}
"}

