import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNull;

import java.math.BigDecimal;
import java.util.List;
import org.junit.jupiter.api.Test;

class TextSanitizerTest {

    record SimpleRecord(String name, String notes, Long id, int count, boolean active) {}

    record NestedRecord(String label, List<SimpleRecord> items) {}

    @Test
    void nullInputReturnsNull() {
        assertNull(TextSanitizer.stripHtmlTags(null));
    }

    @Test
    void plainTextUnchanged() {
        assertEquals("Hello World", TextSanitizer.stripHtmlTags("Hello World"));
    }

    @Test
    void scriptTagsStripped() {
        assertEquals("alert(1)", TextSanitizer.stripHtmlTags("<script>alert(1)</script>"));
    }

    @Test
    void imgTagsStripped() {
        assertEquals("", TextSanitizer.stripHtmlTags("<img src=x onerror=alert(1)>"));
    }

    @Test
    void nestedTagsStripped() {
        assertEquals("Hello", TextSanitizer.stripHtmlTags("<div><b>Hello</b></div>"));
    }

    @Test
    void iframeStripped() {
        assertEquals("", TextSanitizer.stripHtmlTags("<iframe src='https://evil.com'></iframe>"));
    }

    @Test
    void svgOnloadStripped() {
        assertEquals("", TextSanitizer.stripHtmlTags("<svg onload=fetch('/steal')>"));
    }

    @Test
    void sanitizeRecordStripsStringFields() {
        SimpleRecord input = new SimpleRecord("<b>Name</b>", "<script>xss</script>", 42L, 5, true);
        SimpleRecord result = (SimpleRecord) TextSanitizer.sanitizeObject(input);
        assertEquals("Name", result.name());
        assertEquals("xss", result.notes());
        assertEquals(42L, result.id());
        assertEquals(5, result.count());
        assertEquals(true, result.active());
    }

    @Test
    void sanitizeRecordPreservesNullStrings() {
        SimpleRecord input = new SimpleRecord("Clean", null, 1L, 0, false);
        SimpleRecord result = (SimpleRecord) TextSanitizer.sanitizeObject(input);
        assertEquals("Clean", result.name());
        assertNull(result.notes());
    }

    @Test
    void sanitizeRecordWithNestedList() {
        SimpleRecord item1 = new SimpleRecord("<em>A</em>", "<script>bad</script>", 1L, 1, true);
        SimpleRecord item2 = new SimpleRecord("Clean", "Safe text", 2L, 2, false);
        NestedRecord input = new NestedRecord("<b>Label</b>", List.of(item1, item2));

        NestedRecord result = (NestedRecord) TextSanitizer.sanitizeObject(input);
        assertEquals("Label", result.label());
        assertEquals(2, result.items().size());
        assertEquals("A", result.items().get(0).name());
        assertEquals("bad", result.items().get(0).notes());
        assertEquals("Clean", result.items().get(1).name());
        assertEquals("Safe text", result.items().get(1).notes());
    }

    @Test
    void nonRecordObjectReturnedAsIs() {
        BigDecimal value = new BigDecimal("42.50");
        assertEquals(value, TextSanitizer.sanitizeObject(value));
    }

    @Test
    void nullObjectReturnsNull() {
        assertNull(TextSanitizer.sanitizeObject(null));
    }
}
"}

