import org.junit.jupiter.api.Test;
import org.springframework.http.MediaType;

class XssSanitizationIntegrationTest extends AbstractMockMvcIntegrationTest {

    @Test
    void orderNotesXssStripped() throws Exception {
        UserEntity buyer = createUser(RoleName.BUYER, "xss-buyer", "ORG-XSS", "Password!23");

        String body = json(Map.of(
            "items", List.of(Map.of("productId", createProduct(), "quantity", 1)),
            "notes", "<script>alert('xss')</script>Legit notes"
        ));

        String location = mockMvc.perform(post("/api/orders")
                .with(authenticated(buyer))
                .contentType(MediaType.APPLICATION_JSON)
                .content(body))
            .andExpect(status().isCreated())
            .andReturn().getResponse().getHeader("Location");

        String orderId = location.substring(location.lastIndexOf('/') + 1);

        mockMvc.perform(get("/api/orders/" + orderId)
                .with(authenticated(buyer)))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.notes").value("alert('xss')Legit notes"))
            .andExpect(jsonPath("$.notes").value(not(containsString("<script>"))));
    }

    @Test
    void reviewCommentsXssStripped() throws Exception {
        UserEntity buyer = createUser(RoleName.BUYER, "xss-buyer2", "ORG-XSS2", "Password!23");
        UserEntity reviewer = createUser(RoleName.QUALITY_REVIEWER, "xss-quality", "ORG-XSS2", "Password!23");

        var order = createOrder(buyer, OrderStatus.UNDER_REVIEW, 10, 0, 0);

        String reviewBody = json(Map.of(
            "decision", "APPROVE",
            "comments", "<img src=x onerror=alert(1)>Safe comment"
        ));

        mockMvc.perform(post("/api/orders/" + order.getId() + "/review")
                .with(authenticated(reviewer))
                .contentType(MediaType.APPLICATION_JSON)
                .content(reviewBody))
            .andExpect(status().isOk());

        mockMvc.perform(get("/api/orders/" + order.getId())
                .with(authenticated(buyer)))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.review.comments").value("Safe comment"))
            .andExpect(jsonPath("$.review.comments").value(not(containsString("<img"))));
    }

    @Test
    void securityHeadersPresent() throws Exception {
        mockMvc.perform(get("/api/health"))
            .andExpect(status().isOk())
            .andExpect(header().string("X-Content-Type-Options", "nosniff"))
            .andExpect(header().string("X-Frame-Options", "DENY"))
            .andExpect(header().exists("Content-Security-Policy"));
    }

    private Long createProduct() {
        var product = new com.pharmaprocure.portal.entity.ProductCatalogEntity();
