4	import com.pharmaprocure.portal.exception.CaptchaValidationException;
5	import java.time.Clock;
6	import java.time.Instant;
7	import java.util.Map;
8	import java.util.UUID;
9	import java.util.concurrent.ConcurrentHashMap;
10	import org.springframework.stereotype.Service;
11	
12	@Service
13	public class CaptchaService {
14	
15	    private final Map<String, CaptchaChallenge> challenges = new ConcurrentHashMap<>();
16	    private final Clock clock;
17	
18	    public CaptchaService() {
19	        this(Clock.systemUTC());
20	    }
21	
22	    CaptchaService(Clock clock) {
23	        this.clock = clock;
24	    }
25	
26	    public CaptchaChallengeResponse issueChallenge(String username) {
27	        int left = 2 + Math.abs(username.hashCode() % 8);
28	        int right = 3 + Math.abs((username.hashCode() / 7) % 7);
29	        String challengeId = UUID.randomUUID().toString();
30	        challenges.put(challengeId, new CaptchaChallenge(username.toLowerCase(), Integer.toString(left + right), clock.instant().plusSeconds(300)));
31	        return new CaptchaChallengeResponse(challengeId, "What is %d + %d?".formatted(left, right), true);
32	    }
33	
34	    public void validate(String username, String challengeId, String answer) {
35	        CaptchaChallenge challenge = challenges.get(challengeId);
36	        if (challenge == null || challenge.expiresAt().isBefore(clock.instant())) {
37	            throw new CaptchaValidationException(java.util.List.of("CAPTCHA_EXPIRED"));
38	        }
39	        if (!challenge.username().equalsIgnoreCase(username) || answer == null || !challenge.answer().equals(answer.trim())) {
40	            throw new CaptchaValidationException(java.util.List.of("CAPTCHA_INVALID"));
41	        }
42	        challenges.remove(challengeId);
43	    }
44	
45	    private record CaptchaChallenge(String username, String answer, Instant expiresAt) {
46	    }
47	}
