76	    @Transactional
77	    public Page<CriticalActionRequestResponse> list(Pageable pageable, CriticalActionStatus statusFilter) {
78	        UserEntity actor = currentUserService.requireCurrentUser();
79	        permissionAuthorizationService.requireDataScope(actor, Permission.CRITICAL_ACTION_VIEW);
80	        Page<CriticalActionRequestEntity> requests = requestRepository.findAll(pageable);
81	        List<CriticalActionRequestResponse> visible = requests.getContent().stream()
82	            .filter(request -> statusFilter == null || request.getStatus() == statusFilter)
83	            .filter(request -> canAccessTarget(actor, request, Permission.CRITICAL_ACTION_VIEW))
84	            .map(request -> {
85	            expireIfNeeded(request);
86	            return toResponse(request);
87	        }).toList();
88	        return new PageImpl<>(visible, pageable, visible.size());
89	    }
