91	    @Transactional
92	    public CriticalActionRequestResponse create(CreateCriticalActionRequest request) {
93	        UserEntity actor = currentUserService.requireCurrentUser();
94	        CriticalActionRequestType requestType = CriticalActionRequestType.valueOf(request.requestType());
95	        CriticalActionTargetType targetType = CriticalActionTargetType.valueOf(request.targetType());
96	        validateTarget(requestType, targetType, request.targetId(), actor);
97	        requestRepository.findByRequestTypeAndTargetTypeAndTargetIdAndStatusIn(requestType, targetType, request.targetId(), List.of(CriticalActionStatus.PENDING, CriticalActionStatus.PARTIALLY_APPROVED))
98	            .ifPresent(existing -> { throw new ApiException(400, "Active critical action request already exists", List.of("requestId=" + existing.getId())); });
99	
100	        CriticalActionRequestEntity entity = new CriticalActionRequestEntity();
101	        entity.setRequestType(requestType);
102	        entity.setTargetType(targetType);
103	        entity.setTargetId(request.targetId());
104	        entity.setJustification(request.justification());
105	        entity.setRequestedBy(actor);
106	        entity.setStatus(CriticalActionStatus.PENDING);
107	        entity.setCreatedAt(OffsetDateTime.now());
108	        entity.setExpiresAt(OffsetDateTime.now().plusHours(24));
109	        entity = requestRepository.save(entity);
110	        auditService.record(entity, actor, CriticalActionAuditAction.REQUESTED, request.justification());
111	        return toResponse(entity);
112	    }
