114	    @Transactional
115	    public CriticalActionRequestResponse decide(Long requestId, CriticalActionDecision decision, String comments) {
116	        UserEntity actor = currentUserService.requireCurrentUser();
117	        CriticalActionRequestEntity request = requireRequest(requestId, actor, Permission.CRITICAL_ACTION_VIEW);
118	        requireCrossRoleApprover(actor);
119	        expireIfNeeded(request);
120	        if (request.getStatus() == CriticalActionStatus.EXPIRED) {
121	            throw new ApiException(400, "Critical action request has expired", List.of("requestId=" + requestId));
122	        }
123	        if (request.getStatus() == CriticalActionStatus.EXECUTED || request.getStatus() == CriticalActionStatus.REJECTED) {
124	            throw new ApiException(400, "Critical action request is already resolved", List.of(request.getStatus().name()));
125	        }
126	        List<CriticalActionApprovalEntity> existingApprovals = approvalRepository.findByRequestIdOrderByCreatedAtAsc(requestId);
127	        if (existingApprovals.stream().anyMatch(approval -> approval.getApproverUser().getId().equals(actor.getId()))) {
128	            throw new ApiException(400, "The same user cannot approve twice", List.of("SAME_USER_REJECTION"));
129	        }
130	        if (decision == CriticalActionDecision.APPROVE
131	            && existingApprovals.stream().anyMatch(approval -> approval.getDecision() == CriticalActionDecision.APPROVE && approvalLane(approval.getApproverUser()) == approvalLane(actor))) {
132	            throw new ApiException(400, "Critical actions require one quality approval and one finance or system administrator approval", List.of("CROSS_ROLE_APPROVAL_REQUIRED"));
133	        }
134	
135	        CriticalActionApprovalEntity approval = new CriticalActionApprovalEntity();
136	        approval.setRequest(request);
137	        approval.setApproverUser(actor);
138	        approval.setDecision(decision);
139	        approval.setComments(comments);
140	        approval.setCreatedAt(OffsetDateTime.now());
141	        approvalRepository.save(approval);
142	        List<CriticalActionApprovalEntity> approvals = new ArrayList<>(existingApprovals);
143	        approvals.add(approval);
144	
145	        if (decision == CriticalActionDecision.REJECT) {
146	            request.setStatus(CriticalActionStatus.REJECTED);
147	            request.setResolvedAt(OffsetDateTime.now());
148	            request.setResolutionNote(comments == null ? "Rejected" : comments);
149	            auditService.record(request, actor, CriticalActionAuditAction.REJECTED, comments);
150	            return toResponse(request);
151	        }
152	
153	        if (hasRequiredApprovals(approvals)) {
154	            request.setStatus(CriticalActionStatus.APPROVED);
155	            request.setResolvedAt(OffsetDateTime.now());
156	            request.setResolutionNote("Quality and finance or system administrator approvals recorded");
157	            auditService.record(request, actor, CriticalActionAuditAction.APPROVED, "Cross-role approval completed");
158	            execute(request, actor);
159	        } else {
160	            request.setStatus(CriticalActionStatus.PARTIALLY_APPROVED);
161	            auditService.record(request, actor, CriticalActionAuditAction.APPROVED, actor.getRole().getName().name() + " approval recorded");
162	        }
163	        return toResponse(request);
164	    }
