179	            case ORDER_CANCELLATION_AFTER_APPROVAL -> executeOrderCancellation(request, actor);
180	            case DOCUMENT_DESTRUCTION -> executeDocumentDestruction(request, actor);
181	            case RETENTION_OVERRIDE -> executeRetentionOverride(request, actor);
182	        }
183	        request.setStatus(CriticalActionStatus.EXECUTED);
184	        request.setResolvedAt(OffsetDateTime.now());
