200	        document.setStatus(DocumentStatus.DESTROYED);
201	        document.setDestroyedAt(OffsetDateTime.now());
202	        document.setDestroyedBy(actor);
203	        document.setUpdatedAt(OffsetDateTime.now());
204	    }
