213	    private void validateTarget(CriticalActionRequestType requestType, CriticalActionTargetType targetType, Long targetId, UserEntity actor) {
214	        switch (requestType) {
215	            case ORDER_CANCELLATION_AFTER_APPROVAL -> {
216	                if (targetType != CriticalActionTargetType.ORDER) {
217	                    throw new ApiException(400, "Invalid target type for order cancellation", List.of(targetType.name()));
218	                }
219	                ProcurementOrderEntity order = orderRepository.findWithItemsById(targetId)
220	                    .orElseThrow(() -> new ApiException(404, "Order not found", List.of("orderId=" + targetId)));
221	                boolean allowed = permissionAuthorizationService.canAccessResource(
222	                    actor,
223	                    Permission.CRITICAL_ACTION_REQUEST,
224	                    order.getBuyer().getId(),
225	                    order.getBuyer().getRole().getName(),
226	                    order.getBuyer().getOrganizationCode()
227	                );
228	                if (!allowed) {
229	                    throw new ApiException(403, "Access denied", List.of("ORDER_SCOPE_RESTRICTION"));
230	                }
231	                if (order.getCurrentStatus() != OrderStatus.APPROVED && order.getCurrentStatus() != OrderStatus.PAYMENT_RECORDED && order.getCurrentStatus() != OrderStatus.PICK_PACK && order.getCurrentStatus() != OrderStatus.PARTIALLY_SHIPPED && order.getCurrentStatus() != OrderStatus.SHIPPED) {
232	                    throw new ApiException(400, "Only approved or fulfilled orders require critical cancellation", List.of(order.getCurrentStatus().name()));
233	                }
234	            }
235	            case DOCUMENT_DESTRUCTION, RETENTION_OVERRIDE -> {
236	                if (targetType != CriticalActionTargetType.DOCUMENT) {
237	                    throw new ApiException(400, "Invalid target type for document action", List.of(targetType.name()));
238	                }
239	                DocumentEntity document = documentRepository.findWithCurrentVersionById(targetId)
240	                    .orElseThrow(() -> new ApiException(404, "Document not found", List.of("documentId=" + targetId)));
241	                boolean allowed = permissionAuthorizationService.canAccessResource(
242	                    actor,
243	                    Permission.CRITICAL_ACTION_REQUEST,
244	                    document.getOwnerUser().getId(),
245	                    document.getOwnerUser().getRole().getName(),
246	                    document.getOwnerUser().getOrganizationCode()
247	                );
248	                if (!allowed) {
249	                    throw new ApiException(403, "Access denied", List.of("DOCUMENT_SCOPE_RESTRICTION"));
250	                }
251	            }
252	        }
253	    }
