264	    private void expireIfNeeded(CriticalActionRequestEntity request) {
265	        if ((request.getStatus() == CriticalActionStatus.PENDING || request.getStatus() == CriticalActionStatus.PARTIALLY_APPROVED) && request.getExpiresAt().isBefore(OffsetDateTime.now())) {
266	            request.setStatus(CriticalActionStatus.EXPIRED);
