282	        boolean financeOrAdminApproved = approvals.stream().anyMatch(approval -> approval.getDecision() == CriticalActionDecision.APPROVE && "FINANCE_ADMIN".equals(approvalLane(approval.getApproverUser())));
283	        return qualityApproved && financeOrAdminApproved;
