286	    private boolean canAccessTarget(UserEntity actor, CriticalActionRequestEntity request, Permission permission) {
287	        UserEntity requester = request.getRequestedBy();
288	        if (!permissionAuthorizationService.canAccessResource(actor, permission, requester.getId(), requester.getRole().getName(), requester.getOrganizationCode())) {
289	            return false;
290	        }
291	        return switch (request.getTargetType()) {
292	            case ORDER -> orderRepository.findWithItemsById(request.getTargetId())
293	                .map(order -> permissionAuthorizationService.canAccessResource(actor, permission, order.getBuyer().getId(), order.getBuyer().getRole().getName(), order.getBuyer().getOrganizationCode()))
294	                .orElse(false);
295	            case DOCUMENT -> documentRepository.findWithCurrentVersionById(request.getTargetId())
296	                .map(document -> permissionAuthorizationService.canAccessResource(actor, permission, document.getOwnerUser().getId(), document.getOwnerUser().getRole().getName(), document.getOwnerUser().getOrganizationCode()))
297	                .orElse(false);
298	        };
299	    }
