309	    private void appendOrderHistory(ProcurementOrderEntity order, UserEntity actor, OrderStatus from, OrderStatus to, String eventType, String detail) {
310	        OrderStatusHistoryEntity history = new OrderStatusHistoryEntity();
311	        history.setOrder(order);
312	        history.setActorUser(actor);
313	        history.setFromStatus(from == null ? null : from.name());
314	        history.setToStatus(to.name());
315	        history.setEventType(eventType);
316	        history.setDetail(detail);
317	        history.setCreatedAt(OffsetDateTime.now());
318	        orderStatusHistoryRepository.save(history);
