321	    private CriticalActionRequestResponse toResponse(CriticalActionRequestEntity request) {
322	        List<CriticalActionApprovalEntity> approvals = approvalRepository.findByRequestIdOrderByCreatedAtAsc(request.getId());
323	        return new CriticalActionRequestResponse(
324	            request.getId(),
325	            request.getRequestType().name(),
326	            request.getTargetType().name(),
327	            request.getTargetId(),
328	            request.getJustification(),
329	            request.getRequestedBy().getDisplayName(),
330	            request.getStatus().name(),
331	            request.getCreatedAt(),
332	            request.getExpiresAt(),
333	            request.getResolvedAt(),
334	            request.getResolutionNote(),
335	            approvals.size(),
336	            approvals.stream().map(item -> new CriticalActionApprovalResponse(item.getId(), item.getApproverUser().getDisplayName(), item.getDecision().name(), item.getComments(), item.getCreatedAt())).toList(),
337	            auditRepository.findByRequestIdOrderByCreatedAtAsc(request.getId()).stream().map(item -> new CriticalActionAuditResponse(item.getAction().name(), item.getActorUser().getDisplayName(), item.getDetail(), item.getCreatedAt())).toList()
338	        );
