190	        ProcurementOrderEntity order = getManagedOrder(orderId, Permission.ORDER_CREATE);
191	        if (order.getCurrentStatus() == OrderStatus.APPROVED || order.getCurrentStatus() == OrderStatus.PAYMENT_RECORDED || order.getCurrentStatus() == OrderStatus.PICK_PACK || order.getCurrentStatus() == OrderStatus.PARTIALLY_SHIPPED || order.getCurrentStatus() == OrderStatus.SHIPPED || order.getCurrentStatus() == OrderStatus.RECEIVED || order.getCurrentStatus() == OrderStatus.RETURNED) {
192	            throw new ApiException(400, "Approved or fulfilled orders cannot be canceled directly", List.of("Dual approval will be required in a later phase"));
193	        }
194	        OrderStatus from = order.getCurrentStatus();
195	        if (from == OrderStatus.CREATED) {
196	            order.setCurrentStatus(OrderStatus.CANCELED);
197	            order.setUpdatedAt(OffsetDateTime.now());
198	            appendHistory(order, currentUserService.requireCurrentUser(), from, OrderStatus.CANCELED, "ORDER_CANCELED", "Canceled before review");
199	            return toDetail(order);
200	        }
201	        transition(order, OrderStatus.CANCELED, "ORDER_CANCELED", "Canceled before approval");
202	        return toDetail(order);
