4	import java.util.ArrayList;
5	import java.util.List;
6	import org.springframework.stereotype.Service;
7	
8	@Service
9	public class PasswordPolicyService {
10	
11	    public void validateOrThrow(String password) {
12	        List<String> violations = getViolations(password);
13	        if (!violations.isEmpty()) {
14	            throw new ApiException(400, "Password policy violation", violations);
15	        }
16	    }
17	
18	    public boolean isValid(String password) {
19	        return getViolations(password).isEmpty();
20	    }
21	
22	    public List<String> getViolations(String password) {
23	        List<String> violations = new ArrayList<>();
24	        if (password == null || password.length() < 12) {
25	            violations.add("Password must contain at least 12 characters");
26	        }
27	
28	        int characterClasses = 0;
29	        if (password != null && password.chars().anyMatch(Character::isLowerCase)) {
30	            characterClasses++;
31	        }
32	        if (password != null && password.chars().anyMatch(Character::isUpperCase)) {
33	            characterClasses++;
34	        }
35	        if (password != null && password.chars().anyMatch(Character::isDigit)) {
36	            characterClasses++;
37	        }
38	        if (password != null && password.chars().anyMatch(ch -> !Character.isLetterOrDigit(ch))) {
39	            characterClasses++;
40	        }
41	
42	        if (characterClasses < 3) {
43	            violations.add("Password must include at least 3 character classes");
44	        }
45	        return violations;
46	    }
47	}
