1	package com.pharmaprocure.portal.security;
2	
3	import org.springframework.context.annotation.Bean;
4	import org.springframework.context.annotation.Configuration;
5	import org.springframework.http.HttpMethod;
6	import org.springframework.security.authentication.AuthenticationManager;
7	import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
8	import org.springframework.security.config.Customizer;
9	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
10	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
11	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
12	import org.springframework.security.config.http.SessionCreationPolicy;
13	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
14	import org.springframework.security.crypto.password.PasswordEncoder;
15	import org.springframework.security.web.SecurityFilterChain;
16	import org.springframework.security.web.csrf.CsrfTokenRequestAttributeHandler;
17	import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
18	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
19	
20	@Configuration
21	@EnableMethodSecurity
22	public class SecurityConfig {
23	
24	    private final PortalUserDetailsService userDetailsService;
25	    private final JsonAuthenticationEntryPoint authenticationEntryPoint;
26	    private final JsonAccessDeniedHandler accessDeniedHandler;
27	    private final RateLimitFilter rateLimitFilter;
28	
29	    public SecurityConfig(
30	        PortalUserDetailsService userDetailsService,
31	        JsonAuthenticationEntryPoint authenticationEntryPoint,
32	        JsonAccessDeniedHandler accessDeniedHandler,
33	        RateLimitFilter rateLimitFilter
34	    ) {
35	        this.userDetailsService = userDetailsService;
36	        this.authenticationEntryPoint = authenticationEntryPoint;
37	        this.accessDeniedHandler = accessDeniedHandler;
38	        this.rateLimitFilter = rateLimitFilter;
39	    }
40	
41	    @Bean
42	    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
43	        http
44	            .cors(Customizer.withDefaults())
45	            .csrf(csrf -> csrf
46	                .csrfTokenRepository(cookieCsrfTokenRepository())
47	                .csrfTokenRequestHandler(new CsrfTokenRequestAttributeHandler()))
48	            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED))
49	            .authenticationProvider(authenticationProvider())
50	            .authorizeHttpRequests(auth -> auth
51	                .requestMatchers("/api/health", "/api/meta/version", "/actuator/health").permitAll()
52	                .requestMatchers(HttpMethod.GET, "/api/auth/csrf", "/api/auth/captcha").permitAll()
53	                .requestMatchers(HttpMethod.POST, "/api/auth/login").permitAll()
54	                .requestMatchers("/api/admin/**").hasRole("SYSTEM_ADMINISTRATOR")
55	                .requestMatchers("/api/critical-actions/**").hasAnyRole("BUYER", "QUALITY_REVIEWER", "FINANCE", "SYSTEM_ADMINISTRATOR")
56	                .requestMatchers("/api/orders/**").hasAnyRole("BUYER", "FULFILLMENT_CLERK", "QUALITY_REVIEWER", "FINANCE", "SYSTEM_ADMINISTRATOR")
57	                .requestMatchers("/api/documents/**").hasAnyRole("BUYER", "QUALITY_REVIEWER", "SYSTEM_ADMINISTRATOR")
58	                .requestMatchers("/api/check-ins/**").hasAnyRole("BUYER", "SYSTEM_ADMINISTRATOR")
59	                .anyRequest().authenticated())
60	            .exceptionHandling(ex -> ex.authenticationEntryPoint(authenticationEntryPoint).accessDeniedHandler(accessDeniedHandler))
61	            .formLogin(form -> form.disable())
62	            .httpBasic(basic -> basic.disable())
63	            .logout(logout -> logout.disable())
64	            .addFilterAfter(rateLimitFilter, UsernamePasswordAuthenticationFilter.class);
65	
66	        return http.build();
67	    }
68	
69	    @Bean
70	    public DaoAuthenticationProvider authenticationProvider() {
71	        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
72	        provider.setUserDetailsService(userDetailsService);
73	        provider.setPasswordEncoder(passwordEncoder());
74	        return provider;
75	    }
76	
77	    @Bean
78	    public AuthenticationManager authenticationManager(AuthenticationConfiguration configuration) throws Exception {
79	        return configuration.getAuthenticationManager();
80	    }
81	
82	    @Bean
83	    public PasswordEncoder passwordEncoder() {
84	        return new BCryptPasswordEncoder();
85	    }
86	
87	    @Bean
88	    public CookieCsrfTokenRepository cookieCsrfTokenRepository() {
89	        CookieCsrfTokenRepository repository = CookieCsrfTokenRepository.withHttpOnlyFalse();
90	        repository.setCookiePath("/");
91	        return repository;
92	    }
93	}
