1	package com.pharmaprocure.portal.security;
2	
3	import com.fasterxml.jackson.databind.ObjectMapper;
4	import com.pharmaprocure.portal.dto.ApiErrorResponse;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import java.io.IOException;
10	import java.time.Clock;
11	import java.time.Instant;
12	import java.util.ArrayDeque;
13	import java.util.Deque;
14	import java.util.List;
15	import java.util.Map;
16	import java.util.concurrent.ConcurrentHashMap;
17	import org.springframework.http.MediaType;
18	import org.springframework.beans.factory.annotation.Autowired;
19	import org.springframework.security.authentication.AnonymousAuthenticationToken;
20	import org.springframework.security.core.Authentication;
21	import org.springframework.security.core.context.SecurityContextHolder;
22	import org.springframework.stereotype.Component;
23	import org.springframework.web.filter.OncePerRequestFilter;
24	
25	@Component
26	public class RateLimitFilter extends OncePerRequestFilter {
27	
28	    private final int maxRequestsPerMinute;
29	    private final int maxLoginRequestsPerMinute;
30	    private final Map<String, Deque<Instant>> requestWindows = new ConcurrentHashMap<>();
31	    private final Map<String, Deque<Instant>> loginIpWindows = new ConcurrentHashMap<>();
32	    private final Clock clock;
33	    private final ObjectMapper objectMapper;
34	
35	    @Autowired
36	    public RateLimitFilter(
37	            ObjectMapper objectMapper,
38	            @org.springframework.beans.factory.annotation.Value("${rate.limit.max-per-minute:60}") int maxRequestsPerMinute,
39	            @org.springframework.beans.factory.annotation.Value("${rate.limit.login.max-per-minute:20}") int maxLoginRequestsPerMinute) {
40	        this(objectMapper, Clock.systemUTC(), maxRequestsPerMinute, maxLoginRequestsPerMinute);
41	    }
42	
43	    RateLimitFilter(ObjectMapper objectMapper, Clock clock, int maxRequestsPerMinute, int maxLoginRequestsPerMinute) {
44	        this.objectMapper = objectMapper;
45	        this.clock = clock;
46	        this.maxRequestsPerMinute = maxRequestsPerMinute;
47	        this.maxLoginRequestsPerMinute = maxLoginRequestsPerMinute;
48	    }
49	
50	    @Override
51	    protected boolean shouldNotFilter(HttpServletRequest request) {
52	        String path = request.getRequestURI();
53	        return path.startsWith("/api/health") || path.startsWith("/api/meta") || path.startsWith("/actuator")
54	            || path.startsWith("/api/auth/csrf") || path.startsWith("/api/auth/captcha");
55	    }
56	
57	    @Override
58	    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
59	        String path = request.getRequestURI();
60	
61	        if (path.startsWith("/api/auth/login")) {
62	            String clientIp = resolveClientIp(request);
63	            if (isRateLimited(loginIpWindows, clientIp, maxLoginRequestsPerMinute)) {
64	                writeRateLimitResponse(response, "MAX_" + maxLoginRequestsPerMinute + "_LOGIN_REQUESTS_PER_MINUTE");
65	                return;
66	            }
67	            filterChain.doFilter(request, response);
68	            return;
69	        }
70	
71	        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
72	        if (authentication == null || !authentication.isAuthenticated() || authentication instanceof AnonymousAuthenticationToken) {
73	            filterChain.doFilter(request, response);
74	            return;
75	        }
76	
77	        String key = authentication.getName();
78	        if (isRateLimited(requestWindows, key, maxRequestsPerMinute)) {
79	            writeRateLimitResponse(response, "MAX_" + maxRequestsPerMinute + "_REQUESTS_PER_MINUTE");
80	            return;
81	        }
82	
83	        filterChain.doFilter(request, response);
84	    }
85	
86	    private boolean isRateLimited(Map<String, Deque<Instant>> windows, String key, int maxRequests) {
87	        Deque<Instant> window = windows.computeIfAbsent(key, ignored -> new ArrayDeque<>());
88	        Instant now = clock.instant();
89	        synchronized (window) {
90	            while (!window.isEmpty() && window.peekFirst().isBefore(now.minusSeconds(60))) {
91	                window.pollFirst();
92	            }
93	            if (window.size() >= maxRequests) {
94	                return true;
95	            }
96	            window.addLast(now);
97	        }
98	        return false;
99	    }
100	
101	    private void writeRateLimitResponse(HttpServletResponse response, String detail) throws IOException {
102	        response.setStatus(429);
103	        response.setContentType(MediaType.APPLICATION_JSON_VALUE);
104	        objectMapper.writeValue(response.getOutputStream(), new ApiErrorResponse(429, "Rate limit exceeded", List.of(detail)));
105	    }
106	
107	    private String resolveClientIp(HttpServletRequest request) {
108	        String forwarded = request.getHeader("X-Forwarded-For");
109	        if (forwarded != null && !forwarded.isBlank()) {
110	            return forwarded.split(",")[0].trim();
111	        }
112	        return request.getRemoteAddr();
113	    }
114	
115	    public void clearWindows() {
116	        requestWindows.clear();
117	        loginIpWindows.clear();
118	    }
119	}
