1	package com.pharmaprocure.portal.util;
2	
3	import java.util.regex.Pattern;
4	
5	public final class MaskingUtils {
6	
7	    private static final Pattern EMAIL_PATTERN = Pattern.compile("(?i)\\b[\\w.%+-]+@[\\w.-]+\\.[a-z]{2,}\\b");
8	    private static final Pattern LABELED_IDENTIFIER_PATTERN = Pattern.compile("(?i)\\b(username|user|principal|actor|owner|email)(\\s*[:=]\\s*)([^,;\\s]+)");
9	    private static final Pattern INVALID_CREDENTIALS_FOR_PATTERN = Pattern.compile("(?i)(INVALID_CREDENTIALS_FOR\\s*[:=]\\s*)([^,;\\s]+)");
10	
11	    private MaskingUtils() {
12	    }
13	
14	    public static String mask(String raw) {
15	        if (raw == null || raw.isBlank()) {
16	            return "****";
17	        }
18	        int visible = Math.min(4, raw.length());
19	        String suffix = raw.substring(raw.length() - visible);
20	        return "*".repeat(Math.max(raw.length() - visible, 4)) + suffix;
21	    }
22	
23	    public static String sanitizeText(String raw) {
24	        if (raw == null || raw.isBlank()) {
25	            return raw;
26	        }
27	        String sanitized = EMAIL_PATTERN.matcher(raw).replaceAll("[masked-email]");
28	        sanitized = LABELED_IDENTIFIER_PATTERN.matcher(sanitized).replaceAll("$1$2****");
29	        sanitized = INVALID_CREDENTIALS_FOR_PATTERN.matcher(sanitized).replaceAll("$1****");
30	        return sanitized;
31	    }
32	}
