3	import com.pharmaprocure.portal.dto.ApiErrorResponse;
4	import com.pharmaprocure.portal.util.MaskingUtils;
5	import jakarta.validation.ConstraintViolationException;
6	import org.springframework.http.HttpStatus;
7	import org.springframework.http.ResponseEntity;
8	import org.springframework.security.authorization.AuthorizationDeniedException;
9	import org.springframework.security.access.AccessDeniedException;
10	import org.springframework.validation.FieldError;
11	import org.springframework.web.bind.MethodArgumentNotValidException;
12	import org.springframework.web.bind.annotation.ExceptionHandler;
13	import org.springframework.web.bind.annotation.RestControllerAdvice;
14	import org.springframework.web.multipart.MaxUploadSizeExceededException;
15	
16	import java.util.List;
17	
18	@RestControllerAdvice
19	public class GlobalExceptionHandler {
20	
21	    @ExceptionHandler({AccessDeniedException.class, AuthorizationDeniedException.class})
22	    public ResponseEntity<ApiErrorResponse> handleAccessDenied(Exception ex) {
23	        return ResponseEntity.status(HttpStatus.FORBIDDEN)
24	            .body(new ApiErrorResponse(403, "Access denied", List.of("FORBIDDEN")));
25	    }
26	
27	    @ExceptionHandler(ApiException.class)
28	    public ResponseEntity<ApiErrorResponse> handleApiException(ApiException ex) {
29	        String safeMessage = MaskingUtils.sanitizeText(ex.getMessage());
30	        List<String> safeDetails = ex.getDetails() == null
31	            ? List.of()
32	            : ex.getDetails().stream().map(MaskingUtils::sanitizeText).toList();
33	        return ResponseEntity.status(ex.getCode())
34	            .body(new ApiErrorResponse(ex.getCode(), safeMessage, safeDetails));
35	    }
36	
37	    @ExceptionHandler(MaxUploadSizeExceededException.class)
38	    public ResponseEntity<ApiErrorResponse> handleMaxUploadSizeExceeded(MaxUploadSizeExceededException ex) {
39	        return ResponseEntity.badRequest()
40	            .body(new ApiErrorResponse(400, "File exceeds maximum size", List.of("MAX_25_MB")));
41	    }
42	
43	    @ExceptionHandler(MethodArgumentNotValidException.class)
44	    public ResponseEntity<ApiErrorResponse> handleMethodArgumentNotValid(MethodArgumentNotValidException ex) {
45	        List<String> details = ex.getBindingResult()
46	            .getAllErrors()
47	            .stream()
48	            .map(error -> {
49	                if (error instanceof FieldError fieldError) {
50	                    return MaskingUtils.sanitizeText(fieldError.getField() + ": " + fieldError.getDefaultMessage());
51	                }
52	                return MaskingUtils.sanitizeText(error.getDefaultMessage());
53	            })
54	            .toList();
55	
56	        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
57	            .body(new ApiErrorResponse(400, "Validation failed", details));
58	    }
59	
60	    @ExceptionHandler(ConstraintViolationException.class)
61	    public ResponseEntity<ApiErrorResponse> handleConstraintViolation(ConstraintViolationException ex) {
62	        List<String> details = ex.getConstraintViolations().stream()
63	            .map(v -> MaskingUtils.sanitizeText(v.getPropertyPath() + ": " + v.getMessage()))
64	            .toList();
65	        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
66	            .body(new ApiErrorResponse(400, "Validation failed", details));
67	    }
68	
69	    @ExceptionHandler(Exception.class)
70	    public ResponseEntity<ApiErrorResponse> handleGeneralException(Exception ex) {
71	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
72	            .body(new ApiErrorResponse(500, "Unexpected server error", List.of("INTERNAL_ERROR")));
73	    }
74	}
