11	@Service
12	public class AuditService {
13	
14	    private static final Logger LOGGER = LoggerFactory.getLogger(AuditService.class);
15	    private final SystemAuditEventRepository repository;
16	
17	    public AuditService(SystemAuditEventRepository repository) {
18	        this.repository = repository;
19	    }
20	
21	    public void record(String action, String principal) {
22	        String maskedPrincipal = MaskingUtils.mask(principal);
23	        LOGGER.info("audit action={} principal={}", action, maskedPrincipal);
24	        persist(action, maskedPrincipal, null);
25	    }
26	
27	    public void record(String action, String principal, String detail) {
28	        String maskedPrincipal = MaskingUtils.mask(principal);
29	        String sanitizedDetail = MaskingUtils.sanitizeText(detail);
30	        LOGGER.info("audit action={} principal={} detail={}", action, maskedPrincipal, sanitizedDetail);
31	        persist(action, maskedPrincipal, sanitizedDetail);
32	    }
33	
34	    private void persist(String action, String principal, String detail) {
35	        SystemAuditEventEntity event = new SystemAuditEventEntity();
36	        event.setAction(action);
37	        event.setActorUsername(principal == null ? "unknown" : principal);
38	        event.setDetail(detail);
39	        event.setCreatedAt(OffsetDateTime.now());
40	        repository.save(event);
41	    }
42	}
