import static org.springframework.http.MediaType.APPLICATION_JSON;
import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.csrf;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

import com.pharmaprocure.portal.enums.RoleName;
import java.util.Map;
import org.junit.jupiter.api.Test;

/**
 * Verifies that GlobalExceptionHandler applies MaskingUtils.sanitizeText() to
 * error messages before they leave the server, so that sensitive tokens (emails,
 * labeled usernames) are never echoed back in API error responses.
 */
class SanitizationIntegrationTest extends AbstractMockMvcIntegrationTest {

    /**
     * A failed login attempt with a username that looks like an email address must
     * not echo the email back in the 401 response body.
     */
    @Test
    void loginErrorDoesNotLeakEmailInResponse() throws Exception {
        mockMvc.perform(post("/api/auth/login")
                .with(csrf())
                .contentType(APPLICATION_JSON)
                .content(json(Map.of("username", "attacker@evil.com", "password", "wrong"))))
            .andExpect(status().isUnauthorized())
            .andExpect(result -> {
                String body = result.getResponse().getContentAsString();
                assert !body.contains("attacker@evil.com")
                    : "Response must not echo the email address: " + body;
            });
    }

    /**
     * A failed login attempt with a plain username must not echo the raw username
     * string back verbatim in the 401 error detail field.
     */
    @Test
    void loginErrorDoesNotLeakPlainUsernameInDetail() throws Exception {
        createUser(RoleName.BUYER, "buyer-sanit-leak", "ORG-ALPHA", "Password!23");

        mockMvc.perform(post("/api/auth/login")
                .with(csrf())
                .contentType(APPLICATION_JSON)
                .content(json(Map.of("username", "buyer-sanit-leak", "password", "WrongPass1!"))))
            .andExpect(status().isUnauthorized())
            .andExpect(result -> {
                String body = result.getResponse().getContentAsString();
                // The response must contain masked stars, not the literal username
                assert body.contains("****")
                    : "Response details should contain masked stars instead of raw username: " + body;
            });
    }

    /**
     * Sending a request body that fails @NotBlank validation should return a
     * sanitized error — field names are safe to expose, but any user-supplied
     * value embedded in the message should pass through sanitizeText().
     */
    @Test
    void validationErrorResponseContainsSanitizedFieldName() throws Exception {
        var buyer = createUser(RoleName.BUYER, "buyer-sanit-val", "ORG-ALPHA", "Password!23");

        mockMvc.perform(post("/api/orders")
                .with(csrf())
                .with(authenticated(buyer))
                .contentType(APPLICATION_JSON)
                .content("{}"))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.code").value(400))
            .andExpect(jsonPath("$.message").value("Validation failed"))
            .andExpect(jsonPath("$.details").isArray());
    }
}
