7	import com.pharmaprocure.portal.dto.UserSessionResponse;
8	import com.pharmaprocure.portal.entity.UserEntity;
9	import com.pharmaprocure.portal.exception.AccountLockedException;
10	import com.pharmaprocure.portal.exception.CaptchaRequiredException;
11	import com.pharmaprocure.portal.exception.InvalidCredentialsException;
12	import com.pharmaprocure.portal.repository.UserRepository;
13	import com.pharmaprocure.portal.security.UserPrincipal;
14	import jakarta.servlet.http.HttpServletRequest;
15	import jakarta.servlet.http.HttpServletResponse;
16	import jakarta.servlet.http.HttpSession;
17	import java.util.Set;
18	import org.springframework.security.authentication.AuthenticationManager;
