20	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
21	import org.springframework.security.core.Authentication;
22	import org.springframework.security.core.context.SecurityContext;
23	import org.springframework.security.core.context.SecurityContextHolder;
24	import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
25	import org.springframework.stereotype.Service;
26	
27	@Service
28	public class AuthService {
29	
30	    private final UserRepository userRepository;
31	    private final AuthenticationManager authenticationManager;
32	    private final LoginAttemptPolicyService loginAttemptPolicyService;
33	    private final CaptchaService captchaService;
34	    private final AuditService auditService;
35	
36	    public AuthService(
37	        UserRepository userRepository,
38	        AuthenticationManager authenticationManager,
39	        LoginAttemptPolicyService loginAttemptPolicyService,
40	        CaptchaService captchaService,
41	        AuditService auditService
42	    ) {
43	        this.userRepository = userRepository;
44	        this.authenticationManager = authenticationManager;
45	        this.loginAttemptPolicyService = loginAttemptPolicyService;
46	        this.captchaService = captchaService;
47	        this.auditService = auditService;
48	    }
49	
50	    public LoginResponse login(LoginRequest request, HttpServletRequest httpServletRequest, HttpServletResponse httpServletResponse) {
51	        UserEntity user = userRepository.findWithRoleByUsername(request.username())
52	            .orElseThrow(() -> invalidCredentials(request.username()));
53	
54	        if (loginAttemptPolicyService.isLocked(user)) {
55	            auditService.record("LOGIN_FAILURE", request.username(), "LOCKED");
56	            throw new AccountLockedException(java.util.List.of("LOCKED_UNTIL:%s".formatted(user.getLockoutUntil())));
57	        }
58	
59	        if (loginAttemptPolicyService.requiresCaptcha(user)) {
60	            if (request.captchaChallengeId() == null || request.captchaAnswer() == null || request.captchaAnswer().isBlank()) {
61	                throw new CaptchaRequiredException(java.util.List.of("CAPTCHA_REQUIRED"));
62	            }
63	            captchaService.validate(request.username(), request.captchaChallengeId(), request.captchaAnswer());
64	        }
65	
66	        try {
67	            Authentication authentication = authenticationManager.authenticate(
68	                new UsernamePasswordAuthenticationToken(request.username(), request.password())
69	            );
70	
71	            loginAttemptPolicyService.registerSuccess(user);
72	            userRepository.save(user);
73	
74	            SecurityContext context = SecurityContextHolder.createEmptyContext();
75	            context.setAuthentication(authentication);
76	            SecurityContextHolder.setContext(context);
77	
78	            HttpSession previous = httpServletRequest.getSession(false);
79	            if (previous != null) {
80	                previous.invalidate();
81	            }
82	            HttpSession session = httpServletRequest.getSession(true);
83	            session.setAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY, context);
84	
85	            auditService.record("LOGIN_SUCCESS", request.username());
86	            UserPrincipal principal = (UserPrincipal) authentication.getPrincipal();
87	            return new LoginResponse(toSessionResponse(principal), "Login successful");
88	        } catch (BadCredentialsException ex) {
89	            loginAttemptPolicyService.registerFailure(user);
90	            userRepository.save(user);
91	            auditService.record("LOGIN_FAILURE", request.username(), "BAD_CREDENTIALS");
92	            if (loginAttemptPolicyService.isLocked(user)) {
93	                throw new AccountLockedException(java.util.List.of("LOCKED_UNTIL:%s".formatted(user.getLockoutUntil())));
94	            }
95	            if (loginAttemptPolicyService.requiresCaptcha(user)) {
